// Generate FAQs for a service
function generateFAQs(service) {
  const category = service.category;
  const templates = faqTemplates[category] || faqTemplates["Home Services"];
  return templates.map(t => ({
    q: t.q.replace(/{service}/g, service.name).replace(/{serviceLower}/g, service.name.toLowerCase()).replace(/{area}/g, "NYC"),
    a: t.a.replace(/{service}/g, service.name).replace(/{serviceLower}/g, service.name.toLowerCase()).replace(/{area}/g, "NYC"),
  }));
}

// Default common services based on description
function getCommonServices(service) {
  if (commonSvcs[service.slug]) return commonSvcs[service.slug];
  // Extract from description
  const parts = service.description.replace(/\.$/, '').split(/,\s*| and /);
  const cleaned = parts.map(p => p.trim()).filter(p => p.length > 3 && p.length < 60);
  if (cleaned.length >= 3) return cleaned.slice(0, 8);
  return [service.description.replace(/\.$/, '')];
}

